esqlQuery.esql:
FROM metrics-kafkametricsreceiver.otel-*
// Cluster-level broker count (no attributes)
| WHERE kafka.brokers IS NOT NULL
| STATS latest_brokers = MAX(kafka.brokers)
// Threshold: alert when broker count < expected minimum.
// Customise the value below for your cluster (e.g. 2 for HA, 1 for any loss)
| WHERE latest_brokers < 2
